record_types.code:
type stack_entry(kind : stack_entry_type := ST_EMPTY) is
   record
      case kind is
         when ST_EMPTY =>
            null;
         when ST_FRAME =>
            number: Natural;
            next : Natural;
         when ST_VALUE =>
            st_name : string_index;
            st_value : element_type;
      end case;
   end record;
